{
  "mode": "method",
  "tests": [
    {
      "name": "desktop_view_responsive",
      "input": {
        "width": 1280,
        "min_width": 1025,
        "viewport": "desktop"
      },
      "output": "responsive",
      "notes": "Validates that the UI prototype is responsive for desktop sizes."
    },
    {
      "name": "tablet_view_responsive",
      "input": {
        "width": 768,
        "viewport": "tablet"
      },
      "output": "responsive",
      "notes": "Checks that the UI prototype is responsive for tablet sizes."
    },
    {
      "name": "mobile_view_responsive",
      "input": {
        "width": 750,
        "viewport": "mobile"
      },
      "output": "responsive",
      "notes": "Ensures the UI prototype is responsive for mobile sizes."
    },
    {
      "name": "hover_state_consistency",
      "input": {
        "button_states": ["default", "hover"]
      },
      "output": "consistent",
      "notes": "Tests that hover states are consistent across all buttons."
    },
    {
      "name": "tooltip_functionality",
      "input": {
        "button_id": "submit",
        "tooltip": "Submit your data"
      },
      "output": "tooltip_visible",
      "notes": "Validates that tooltips are functioning correctly for buttons."
    },
    {
      "name": "json_data_loading",
      "input": {
        "page": "dashboard",
        "data_source": "dashboard_data.json"
      },
      "output": "data_loaded",
      "notes": "Checks that data is correctly loaded from the specified JSON file."
    },
    {
      "name": "sass_usage_check",
      "input": {
        "css_files": ["styles.scss"]
      },
      "output": "sass_used",
      "notes": "Ensures that SASS/SCSS is used for styling instead of raw CSS."
    },
    {
      "name": "edge_case_min_width",
      "input": {
        "width": 1025,
        "viewport": "desktop"
      },
      "output": "responsive",
      "notes": "Tests the minimum width edge case for desktop responsiveness."
    }
  ],
  "assumptions": "The UI prototype must adhere to the specified design and functionality requirements.",
  "notes": "Ensure all tests are run in the specified viewport sizes."
}
